import{_ as s,o as e,c as a,aw as n}from"./chunks/framework.Dq2onT5h.js";const o=JSON.parse('{"title":"Evolve Metrics Guide","description":"","frontmatter":{"head":[["meta",{"name":"og:title","content":"Evolve Metrics Guide | Evolve"},{"name":"og:description","content":false}]]},"headers":[],"relativePath":"guides/operations/monitoring.md","filePath":"guides/operations/monitoring.md","lastUpdated":1772446570000}');const l=s({name:"guides/operations/monitoring.md"},[["render",function(s,o,l,t,i,r){return e(),a("div",null,[...o[0]||(o[0]=[n('<h1 id="evolve-metrics-guide" tabindex="-1">Evolve Metrics Guide <a class="header-anchor" href="#evolve-metrics-guide" aria-label="Permalink to &quot;Evolve Metrics Guide&quot;">​</a></h1><h2 id="how-to-configure-metrics" tabindex="-1">How to configure metrics <a class="header-anchor" href="#how-to-configure-metrics" aria-label="Permalink to &quot;How to configure metrics&quot;">​</a></h2><p>Evolve can report and serve Prometheus metrics, which can be consumed by Prometheus collector(s).</p><p>This functionality is disabled by default.</p><p>To enable Prometheus metrics, set <code>instrumentation.prometheus=true</code> in your Evolve node&#39;s configuration file.</p><p>Metrics will be served under <code>/metrics</code> on port 26660 by default. The listening address can be changed using the <code>instrumentation.prometheus_listen_addr</code> configuration option.</p><h2 id="list-of-available-metrics" tabindex="-1">List of available metrics <a class="header-anchor" href="#list-of-available-metrics" aria-label="Permalink to &quot;List of available metrics&quot;">​</a></h2><p>You can find the full list of available metrics in the <a href="./../learn/specs/block-manager#metrics">Technical Specifications</a>.</p><h2 id="viewing-metrics" tabindex="-1">Viewing Metrics <a class="header-anchor" href="#viewing-metrics" aria-label="Permalink to &quot;Viewing Metrics&quot;">​</a></h2><p>Once your Evolve node is running with metrics enabled, you can view the metrics by:</p><ol><li><p>Accessing the metrics endpoint directly:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">curl</span><span style="color:#BFF3C2;"> http://localhost:26660/metrics</span></span></code></pre></div></li><li><p>Configuring Prometheus to scrape these metrics by adding the following to your <code>prometheus.yml</code>:</p><div class="language-yaml"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">scrape_configs</span><span style="color:#767676;">:</span></span>\n<span class="line"><span style="color:#767676;">  -</span><span style="color:#94EEFF;"> job_name</span><span style="color:#767676;">:</span><span style="color:#BFF3C2;"> evolve</span></span>\n<span class="line"><span style="color:#94EEFF;">    static_configs</span><span style="color:#767676;">:</span></span>\n<span class="line"><span style="color:#767676;">      -</span><span style="color:#94EEFF;"> targets</span><span style="color:#767676;">:</span><span style="color:#767676;"> [</span><span style="color:#BFF3C280;">&#39;</span><span style="color:#BFF3C2;">localhost:26660</span><span style="color:#BFF3C280;">&#39;</span><span style="color:#767676;">]</span></span></code></pre></div></li><li><p>Using Grafana with Prometheus as a data source to visualize the metrics.</p></li></ol><h2 id="example-prometheus-configuration" tabindex="-1">Example Prometheus Configuration <a class="header-anchor" href="#example-prometheus-configuration" aria-label="Permalink to &quot;Example Prometheus Configuration&quot;">​</a></h2><p>Here&#39;s a basic Prometheus configuration to scrape metrics from a Evolve node:</p><div class="language-yaml"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">global</span><span style="color:#767676;">:</span></span>\n<span class="line"><span style="color:#94EEFF;">  scrape_interval</span><span style="color:#767676;">:</span><span style="color:#BFF3C2;"> 15s</span></span>\n<span class="line"><span style="color:#94EEFF;">  evaluation_interval</span><span style="color:#767676;">:</span><span style="color:#BFF3C2;"> 15s</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#94EEFF;">scrape_configs</span><span style="color:#767676;">:</span></span>\n<span class="line"><span style="color:#767676;">  -</span><span style="color:#94EEFF;"> job_name</span><span style="color:#767676;">:</span><span style="color:#BFF3C2;"> evolve</span></span>\n<span class="line"><span style="color:#94EEFF;">    static_configs</span><span style="color:#767676;">:</span></span>\n<span class="line"><span style="color:#767676;">      -</span><span style="color:#94EEFF;"> targets</span><span style="color:#767676;">:</span><span style="color:#767676;"> [</span><span style="color:#BFF3C280;">&#39;</span><span style="color:#BFF3C2;">localhost:26660</span><span style="color:#BFF3C280;">&#39;</span><span style="color:#767676;">]</span></span></code></pre></div><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><p>If you&#39;re not seeing metrics:</p><ol><li>Ensure metrics are enabled in your configuration with <code>instrumentation.prometheus=true</code></li><li>Verify the metrics endpoint is accessible: <code>curl http://localhost:26660/metrics</code></li><li>Check your Prometheus configuration is correctly pointing to your Evolve node</li><li>Examine the Evolve node logs for any errors related to the metrics server</li></ol><h2 id="advanced-configuration" tabindex="-1">Advanced Configuration <a class="header-anchor" href="#advanced-configuration" aria-label="Permalink to &quot;Advanced Configuration&quot;">​</a></h2><p>For more advanced metrics configuration, you can adjust the following settings in your configuration file:</p><div class="language-yaml"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">instrumentation</span><span style="color:#767676;">:</span></span>\n<span class="line"><span style="color:#94EEFF;">  prometheus</span><span style="color:#767676;">:</span><span style="color:#FFECB6;"> true</span></span>\n<span class="line"><span style="color:#94EEFF;">  prometheus_listen_addr</span><span style="color:#767676;">:</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">:26660</span><span style="color:#BFF3C280;">&quot;</span></span>\n<span class="line"><span style="color:#94EEFF;">  max_open_connections</span><span style="color:#767676;">:</span><span style="color:#FFECB6;"> 3</span></span>\n<span class="line"><span style="color:#94EEFF;">  namespace</span><span style="color:#767676;">:</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">evolve</span><span style="color:#BFF3C280;">&quot;</span></span></code></pre></div><p>These settings allow you to:</p><ul><li>Enable/disable Prometheus metrics</li><li>Change the listening address for the metrics server</li><li>Limit the maximum number of open connections to the metrics server</li><li>Set a custom namespace for all metrics</li></ul>',22)])])}]]);export{o as __pageData,l as default};
